import React, { useRef, useCallback, useState, useEffect } from 'react';
import './styles.css'
import ProgressBar from './ProgressBar'
import { useProgressStore } from './useProgressStore';

function ProgressBars() {
    const { bars, addBar, setCurrentBar, currentBar, nextId } = useProgressStore((state) => state)

    function startNext() {
        if (currentBar !== null) return;
        if (!nextId) return;
        setCurrentBar(nextId)
        updateBars(nextId, true)
    }

    useEffect(() => {
        startNext()
    }, [currentBar])

    function handleComplete(id) {
        if (currentBar === id) {
            setCurrentBar(null)
        }
        updateBars(id, false)
        startNext();
    }

    return (
        <>
            <div>
                {bars.map((bar, idx) => (
                    <ProgressBar key={bar.id}
                        active={bar.active}
                        duration={1000}
                        onComplete={() => handleComplete(bar.id)} />
                ))}
            </div>
            <button onClick={addBar}>+Add</button>
        </>
    )
}

export default ProgressBars
